def _submit_bounded(fn):
    """Submit to the shared pool, refusing if all worker slots are already in
    flight (i.e. leaked to hung backends). Decrements the count when the future
    completes — a leaked worker keeps its slot counted until it finally returns."""
    global _inflight
    with _inflight_lock:
        if _inflight >= _TIMEOUT_POOL_WORKERS:
            raise ReasoningError(
                f"reasoning timeout pool saturated ({_inflight}/{_TIMEOUT_POOL_WORKERS} "
                "workers in-flight) — hung backend call(s) have leaked every worker slot"
            )
        _inflight += 1

    def _release(_):
        global _inflight
        with _inflight_lock:
            _inflight -= 1

    # Submit only after incrementing, but if submit() itself raises (e.g. the pool
    # was shut down — "cannot schedule new futures after shutdown") the done-callback
    # never fires, so decrement here to avoid permanently leaking the slot and
    # eventually false-saturating the pool (pass-5).
    try:
        future = _timeout_pool.submit(fn)
    except BaseException:
        with _inflight_lock:
            _inflight -= 1
        raise
    future.add_done_callback(_release)
    return future

